class Solution:
    def isInterleave(self, s1: str, s2: str, s3: str) -> bool:
        m, n = len(s1), len(s2)
        if m + n != len(s3): return False
        dp = [[False]*(n+1) for _ in range(m+1)]
        dp[0][0] = True
        for i in range(m+1):
            for j in range(n+1):
                k = i + j
                if i and s1[i-1]==s3[k-1]: dp[i][j] |= dp[i-1][j]
                if j and s2[j-1]==s3[k-1]: dp[i][j] |= dp[i][j-1]
        return dp[m][n]

